from collections import deque
class Solution:
    def longestSubarray(self, nums, limit):
        max_dq = deque()  # descending
        min_dq = deque()  # ascending
        l = 0
        best = 0
        for r, v in enumerate(nums):
            while max_dq and nums[max_dq[-1]] <= v:
                max_dq.pop()
            max_dq.append(r)
            while min_dq and nums[min_dq[-1]] >= v:
                min_dq.pop()
            min_dq.append(r)
            while nums[max_dq[0]] - nums[min_dq[0]] > limit:
                l += 1
                if max_dq[0] < l:
                    max_dq.popleft()
                if min_dq[0] < l:
                    min_dq.popleft()
            best = max(best, r - l + 1)
        return best

